UPDATE chat_room_member
SET last_read_at = CURRENT_TIMESTAMP
WHERE room_id = #{roomId}
  AND member_id = #{memberId}
  AND deleted_yn = 'N'

UPDATE chat_room_member
SET deleted_yn = 'Y',
    left_at = CURRENT_TIMESTAMP
WHERE room_id = #{roomId}
  AND member_id = #{memberId}
  AND deleted_yn = 'N'

UPDATE chat_room
SET deleted_yn = 'Y'
WHERE room_id = #{roomId}
  AND NOT EXISTS (
      SELECT 1
      FROM chat_room_member crm
      WHERE crm.room_id = #{roomId}
        AND crm.deleted_yn = 'N'
  )
